import base64
import io
from functools import lru_cache

from PIL import Image


ROBOT_PNG = {
    'r': (
        ''
    ),
    'd': (
        ''
    ),
    'u': (
        ''
    ),
    'l': (
        ''
    )
}

BEEPER_JPEG = (
    ''
)


def _decode_image(data):
    raw = base64.b64decode(data)
    image = Image.open(io.BytesIO(raw))
    return image.convert('RGBA')


@lru_cache(maxsize=None)
def get_robot_image(direction):
    key = direction.lower()[0]
    if key not in ROBOT_PNG:
        key = 'r'
    return _decode_image(ROBOT_PNG[key])


@lru_cache(maxsize=None)
def get_beeper_image():
    return _decode_image(BEEPER_JPEG)
